#include <stdio.h>
int main() {
    int x = 25;          // Regular integer variable
    int *ptr;            // Declaration: pointer to int

    ptr = &x;            // Initialize with address of x

    printf("Value of x: %d\n", x);
    printf("Address of x: %p\n", &x);
    printf("Value of ptr: %p\n", ptr);
    printf("Value at ptr: %d\n", *ptr);

    *ptr = 100;         // Modify x through pointer
    printf("Modified x: %d\n", x);

    return 0;
}

#include <stdio.h>
int main() {
    int arr[5] = {10, 20, 30, 40, 50};
    int *p = arr;        // Points to first element (arr[0])

    printf("Using pointer arithmetic:\n");
    for(int i = 0; i < 5; i++) {
        printf("*(p + %d) = %d\n", i, *(p + i));
    }

    printf("\nArray notation equivalence:\n");
    for(int i = 0; i < 5; i++) {
        printf("arr[%d] = %d  *(arr+%d) = %d\n", i, arr[i], i, *(arr+i));
    }

    printf("\nPointer increment demonstration:\n");
    p = arr;
    printf("Initial: *p = %d\n", *p++);  // Print then increment
    printf("After post++: *p = %d\n", *p);

    return 0;
}

#include <stdio.h>
#include <stdlib.h>

int main() {
    int n, *arr;
    printf("Enter number of elements: ");
    scanf("%d", &n);

    // Allocate memory for n integers
    arr = (int*)malloc(n * sizeof(int));

    // Check if allocation succeeded
    if(arr == NULL) {
        printf("Memory allocation failed!\n");
        return 1;
    }

    // Fill array with values
    printf("Enter %d integers:\n", n);
    for(int i = 0; i < n; i++) {
        scanf("%d", arr + i);  // or (arr+i) same as &arr[i]
    }

    // Display values
    printf("Array elements: ");
    for(int i = 0; i < n; i++) {
        printf("%d ", *(arr + i));
    }
    printf("\n");

    // Free allocated memory
    free(arr);

    return 0;
}

#include <stdio.h>
#include <stdlib.h>

void allocateMemory(int **ptr, int size) {
    *ptr = (int*)malloc(size * sizeof(int));
}

void modifyValue(int *ptr) {
    *ptr = 500;
}

int main() {
    int *p = NULL;
    int **pp = &p;       // Double pointer

    // Using double pointer to allocate memory
    allocateMemory(pp, 5);

    if(p != NULL) {
        printf("Memory allocated successfully!\n");
        printf("p points to address: %p\n", (void*)p);

        // Modify value through pointer
        modifyValue(p);
        printf("Value at *p: %d\n", *p);

        free(p);
    }

    // Another example: modify pointer directly
    int x = 10, y = 20;
    int *ptr1 = &x;
    int *ptr2 = &y;

    printf("\nBefore swap: ptr1=%d, ptr2=%d\n", *ptr1, *ptr2);

    // Swap the pointers using double pointer
    int *temp;
    temp = ptr1;
    ptr1 = ptr2;
    ptr2 = temp;

    printf("After swap: ptr1=%d, ptr2=%d\n", *ptr1, *ptr2);

    return 0;
}
